const input = $input.first().json;
const body = input.body ?? input;

if (body.data?.key?.fromMe === true) return [];
if (body.event && body.event !== 'messages.upsert') return [];
const data = body.data || {};
const remoteJid = data.key?.remoteJid;
if (!remoteJid) return [];
if (remoteJid.endsWith('@g.us')) return [];

const telefone = (remoteJid.split('@')[0] || '').replace(/\D/g, '');

let texto = '';
if (data.message?.conversation) texto = data.message.conversation;
else if (data.message?.extendedTextMessage?.text) texto = data.message.extendedTextMessage.text;
else if (data.message?.imageMessage?.caption) texto = data.message.imageMessage.caption;
texto = (texto || '').trim();

const sd = $getWorkflowStaticData('global');
let modo = sd.modo || 'pizzaria';

const ownerRaw = ($env.DEMO_OWNER_NUMBER || '').replace(/\D/g, '');
const isOwner = ownerRaw ? telefone.endsWith(ownerRaw.slice(-8)) : true;

const base = 'https://n8n.kronosintelligence.com.br';
const nomeModo = { pizzaria: 'Pizzaria Bella Massa 🍕', aurora: 'Clínica Aurora 💆', resumo: 'Resumo de Áudio 🎙️' };

if (isOwner && texto.startsWith('/')) {
  const cmd = texto.toLowerCase().split(/\s+/)[0];
  if (cmd === '/pizzaria' || cmd === '/aurora' || cmd === '/resumo') {
    modo = cmd.slice(1);
    sd.modo = modo;
    return [{ json: { acao: 'cmd', remoteJid, resposta: `✅ Chavinha trocada!\nAgora a demo é: *${nomeModo[modo]}*\n\nPode mandar mensagem que eu respondo nesse modo.` } }];
  }
  if (cmd === '/status') {
    return [{ json: { acao: 'cmd', remoteJid, resposta: `📍 Modo atual: *${nomeModo[modo]}*\n\nComandos: /pizzaria · /aurora · /resumo` } }];
  }
  return [{ json: { acao: 'cmd', remoteJid, resposta: `🎛️ *Central de Demos Kronos*\nComandos:\n/pizzaria — Bella Massa\n/aurora — Clínica Aurora\n/resumo — Resumo de áudio\n/status — ver modo atual` } }];
}

if (modo === 'aurora') {
  return [{ json: { acao: 'cmd', remoteJid, resposta: '🔧 A demo da Aurora entra na próxima atualização. Por enquanto, manda */pizzaria* ou */resumo* 🙂' } }];
}

const urls = { pizzaria: base + '/webhook/whatsapp-santaana', resumo: base + '/webhook/whatsapp-resumo' };
return [{ json: { acao: 'forward', modo, remoteJid, forwardUrl: urls[modo], body } }];
